     1|/**
     2| * Admin Reels API client — owner management of project reels and deal videos.
     3| * Migrated from ios-ivx/Ivx/Services/AdminReelsService.swift
     4| *
     5| * Backend endpoints:
     6| *   GET  /api/ivx/video-platform/admin/videos        — list all (including hidden)
     7| *   POST /api/ivx/video-platform/admin/add-reel       — add new video by URL
     8| *   POST /api/ivx/video-platform/admin/videos/:id     — update/hide/feature/delete
     9| */
    10|
    11|const API_BASE = (process.env.EXPO_PUBLIC_IVX_API_BASE_URL || 'https://api.ivxholding.com').replace(/\/+$/, '');
    12|
    13|export interface AdminVideo {
    14|  id: string;
    15|  project_id: string | null;
    16|  video_url: string;
    17|  hls_url: string | null;
    18|  poster_url: string | null;
    19|  thumbnail_url: string | null;
    20|  title: string | null;
    21|  duration_sec: number | null;
    22|  width: number | null;
    23|  height: number | null;
    24|  orientation: string | null;
    25|  is_approved: boolean;
    26|  is_pinned: boolean;
    27|  created_at: string;
    28|  video_type: 'deal' | 'reel';
    29|  is_featured: boolean;
    30|  is_hidden: boolean;
    31|  status: string | null;
    32|  display_order: number | null;
    33|}
    34|
    35|export interface AdminVideosResponse {
    36|  videos: AdminVideo[];
    37|  count: number;
    38|  total?: number;
    39|}
    40|
    41|export interface AddReelResponse {
    42|  ok: boolean;
    43|  videoId?: string;
    44|  title?: string;
    45|  videoType?: string;
    46|  videoUrl?: string;
    47|  error?: string;
    48|}
    49|
    50|/**
    51| * List all videos for admin management (includes hidden/draft).
    52| */
    53|export async function fetchAllVideos(type?: string): Promise<AdminVideo[]> {
    54|  const path = type && type !== 'all'
    55|    ? `/api/ivx/video-platform/admin/videos?type=${type}`
    56|    : `/api/ivx/video-platform/admin/videos`;
    57|  const res = await fetch(`${API_BASE}${path}`, {
    58|    method: 'GET',
    59|    headers: { 'Accept': 'application/json' },
    60|  });
    61|  if (!res.ok) throw new Error(`Admin videos request failed (${res.status})`);
    62|  const data = (await res.json()) as AdminVideosResponse;
    63|  return Array.isArray(data.videos) ? data.videos : [];
    64|}
    65|
    66|/**
    67| * Add a new reel/deal video by URL — no developer needed.
    68| */
    69|export async function addVideo(params: {
    70|  videoUrl: string;
    71|  title: string;
    72|  videoType: string;
    73|  projectId?: string;
    74|  posterUrl?: string;
    75|  durationSec?: number;
    76|}): Promise<AddReelResponse> {
    77|  const res = await fetch(`${API_BASE}/api/ivx/video-platform/admin/add-reel`, {
    78|    method: 'POST',
    79|    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
    80|    body: JSON.stringify({
    81|      video_url: params.videoUrl,
    82|      title: params.title,
    83|      video_type: params.videoType,
    84|      ...(params.projectId ? { project_id: params.projectId } : {}),
    85|      ...(params.posterUrl ? { poster_url: params.posterUrl } : {}),
    86|      ...(params.durationSec ? { duration_sec: params.durationSec } : {}),
    87|    }),
    88|  });
    89|  const data = (await res.json()) as AddReelResponse;
    90|  if (!res.ok) throw new Error(data.error || `HTTP ${res.status}`);
    91|  return data;
    92|}
    93|
    94|/**
    95| * Update a video: hide/show, change type, set display order, feature, or delete.
    96| */
    97|export async function updateVideo(params: {
    98|  videoId: string;
    99|  action: string;
   100|  videoType?: string;
   101|  isHidden?: boolean;
   102|  isFeatured?: boolean;
   103|  displayOrder?: number;
   104|  title?: string;
   105|}): Promise<void> {
   106|  const res = await fetch(`${API_BASE}/api/ivx/video-platform/admin/videos/${params.videoId}`, {
   107|    method: 'POST',
   108|    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
   109|    body: JSON.stringify({
   110|      action: params.action,
   111|      ...(params.videoType ? { video_type: params.videoType } : {}),
   112|      ...(params.isHidden !== undefined ? { is_hidden: params.isHidden } : {}),
   113|      ...(params.isFeatured !== undefined ? { is_featured: params.isFeatured } : {}),
   114|      ...(params.displayOrder !== undefined ? { display_order: params.displayOrder } : {}),
   115|      ...(params.title ? { title: params.title } : {}),
   116|    }),
   117|  });
   118|  if (!res.ok) {
   119|    const text = await res.text().catch(() => `HTTP ${res.status}`);
   120|    throw new Error(text);
   121|  }
   122|}
   123|
   124|export async function deleteVideo(videoId: string): Promise<void> {
   125|  await updateVideo({ videoId, action: 'delete' });
   126|}
   127|
   128|export async function toggleVideoVisibility(videoId: string, isHidden: boolean): Promise<void> {
   129|  await updateVideo({ videoId, action: 'toggle_visibility', isHidden: !isHidden });
   130|}
