   133|  await updateVideo({ videoId, action: 'toggle_featured', isFeatured: !isFeatured });
   134|}
   135|
   136|export async function reorderVideo(videoId: string, displayOrder: number): Promise<void> {
   137|  await updateVideo({ videoId, action: 'reorder', displayOrder });
